/* -----------------------------------------------
    Debugging and error handling
   ----------------------------------------------- */
static void ErrLog(const CHAR *sFormat, ...)
{
    va_list argp;
    va_start(argp, sFormat);
    vsnprintf(gsLSCPCIEJ_LastErr, sizeof(gsLSCPCIEJ_LastErr) - 1, sFormat, argp);
#if defined(DEBUG)
#if defined(__KERNEL__)
    WDC_Err("KP LSCPCIEJ lib: %s", LSCPCIEJ_GetLastErr());
#else
    WDC_Err("LSCPCIEJ lib: %s", LSCPCIEJ_GetLastErr());
#endif
#endif
    va_end(argp);
}

static void TraceLog(const CHAR *sFormat, ...)
{
#if defined(DEBUG)
    CHAR sMsg[256];
    va_list argp;
    va_start(argp, sFormat);
    vsnprintf(sMsg, sizeof(sMsg) - 1, sFormat, argp);
#if defined(__KERNEL__)
    WDC_Trace("KP LSCPCIEJ lib: %s", sMsg);
#else
    WDC_Trace("LSCPCIEJ lib: %s", sMsg);
#endif
    va_end(argp);
#endif
}

const char *LSCPCIEJ_GetLastErr(void)
{
    return gsLSCPCIEJ_LastErr;
}
